// src/pages/Home.jsx
import React, { useState, useEffect } from 'react';
import { motion } from 'framer-motion';
import SearchBar from '../components/SearchBar';
import CourseCard from '../components/CourseCard';
import StatsCard from '../components/StatsCard';
import { getCourses } from '../services/coursesService';
import './Home.css';

const Home = () => {
  const [courses, setCourses] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    fetchCourses();
  }, []);

  const fetchCourses = async () => {
    try {
      const data = await getCourses();
      setCourses(data.slice(0, 6)); // Show only 6 courses on homepage
    } catch (error) {
      console.error('Error fetching courses:', error);
    } finally {
      setLoading(false);
    }
  };

  const stats = [
    { title: 'Total Notes', value: '500+', icon: '📄' },
    { title: 'PYQs', value: '1000+', icon: '📝' },
    { title: 'Courses', value: '50+', icon: '🎓' },
    { title: 'Downloads', value: '2000+', icon: '⬇️' },
  ];

  return (
    <div className="home-page">
      {/* Hero Section */}
      <section className="hero-section">
        <motion.div
          initial={{ opacity: 0, y: 50 }}
          animate={{ opacity: 1, y: 0 }}
          transition={{ duration: 0.8 }}
          className="hero-content"
        >
          <h1 className="hero-title">
            Welcome to <span className="highlight">College Notes Hub</span>
          </h1>
          <p className="hero-subtitle">
            Your one-stop destination for notes, PYQs, syllabus, and study materials
          </p>
          <SearchBar />
        </motion.div>
      </section>

      {/* Stats Section */}
      <section className="stats-section">
        <div className="stats-grid">
          {stats.map((stat, index) => (
            <StatsCard key={index} {...stat} />
          ))}
        </div>
      </section>

      {/* Featured Courses */}
      <section className="courses-section">
        <h2 className="section-title">Featured Courses</h2>
        {loading ? (
          <div className="loading">Loading courses...</div>
        ) : (
          <div className="courses-grid">
            {courses.map((course) => (
              <CourseCard key={course.id} course={course} />
            ))}
          </div>
        )}
        <div className="view-all">
          <button className="view-all-btn">View All Courses →</button>
        </div>
      </section>

      {/* Features Section */}
      <section className="features-section">
        <h2 className="section-title">Why Choose Notes Hub?</h2>
        <div className="features-grid">
          <div className="feature-card">
            <div className="feature-icon">✅</div>
            <h3>Updated Content</h3>
            <p>Regularly updated notes and PYQs</p>
          </div>
          <div className="feature-card">
            <div className="feature-icon">🔍</div>
            <h3>Easy Search</h3>
            <p>Find materials quickly with smart search</p>
          </div>
          <div className="feature-card">
            <div className="feature-icon">📱</div>
            <h3>Mobile Friendly</h3>
            <p>Access on any device, anywhere</p>
          </div>
          <div className="feature-card">
            <div className="feature-icon">🆓</div>
            <h3>Free Forever</h3>
            <p>All resources completely free</p>
          </div>
        </div>
      </section>
    </div>
  );
};

export default Home;
